import * as React from 'react';
const { useState, useEffect } = React;
import { timelineData } from '../mock-datas/journey.data';

type Phase = 'idle' | 'exit' | 'enter';
type ExitDir = 'up' | 'down';

const JourneySection: React.FC = () => {
  const bgImage = '/assets/images/wp1.jpg';

  const [displayIndex, setDisplayIndex] = useState(0);
  const [pendingIndex, setPendingIndex] = useState<number | null>(null);
  const [phase, setPhase] = useState<Phase>('idle');
  const [exitDir, setExitDir] = useState<ExitDir>('up');
  const [animKey, setAnimKey] = useState(0);

  // Lock page scroll while this full-screen section is mounted
  useEffect(() => {
    const prev = document.documentElement.style.overflow;
    document.documentElement.style.overflow = 'hidden';
    return () => { document.documentElement.style.overflow = prev; };
  }, []);

  const navigate = (dir: 'next' | 'prev') => {
    if (phase !== 'idle') return;
    const newIndex = dir === 'next' ? displayIndex + 1 : displayIndex - 1;
    if (newIndex < 0 || newIndex >= timelineData.length) return;
    setPendingIndex(newIndex);
    setExitDir(dir === 'next' ? 'up' : 'down');
    setPhase('exit');
  };

  const handleAnimationEnd = (e: React.AnimationEvent<HTMLDivElement>) => {
    // Only respond to the wrapper's own animation, not bubbled child animations
    if (e.target !== e.currentTarget) return;
    if (phase === 'exit' && pendingIndex !== null) {
      setDisplayIndex(pendingIndex);
      setPendingIndex(null);
      setAnimKey((k) => k + 1);
      setPhase('enter');
    } else if (phase === 'enter') {
      setPhase('idle');
    }
  };

  const currentData = timelineData[displayIndex];

  const carouselClass = [
    phase === 'exit'
      ? (exitDir === 'up' ? 'jtl-exit-up' : 'jtl-exit-down')
      : phase === 'enter'
      ? (exitDir === 'up' ? 'jtl-enter-up' : 'jtl-enter-down')
      : '',
  ].filter(Boolean).join(' ');

  return (
    <>
      <style>{`
        /* ── Carousel animations ── */
        @keyframes jtlExitUp {
          from { transform: translateY(0);    opacity: 1; }
          to   { transform: translateY(-36px); opacity: 0; }
        }
        @keyframes jtlExitDown {
          from { transform: translateY(0);    opacity: 1; }
          to   { transform: translateY(36px); opacity: 0; }
        }
        @keyframes jtlEnterUp {
          from { transform: translateY(36px); opacity: 0; }
          to   { transform: translateY(0);    opacity: 1; }
        }
        @keyframes jtlEnterDown {
          from { transform: translateY(-36px); opacity: 0; }
          to   { transform: translateY(0);     opacity: 1; }
        }
        .jtl-exit-up    { animation: jtlExitUp   0.32s ease-out both; }
        .jtl-exit-down  { animation: jtlExitDown  0.32s ease-out both; }
        .jtl-enter-up   { animation: jtlEnterUp   0.32s ease-out both; }
        .jtl-enter-down { animation: jtlEnterDown 0.32s ease-out both; }

        /* ── Event item animations ── */
        @keyframes jtlCircle {
          from { transform: scale(0); opacity: 0; }
          to   { transform: scale(1); opacity: 1; }
        }
        @keyframes jtlHLine {
          from { transform: scaleX(0); }
          to   { transform: scaleX(1); }
        }
        @keyframes jtlVLine {
          from { transform: scaleY(0); }
          to   { transform: scaleY(1); }
        }
        @keyframes jtlCard {
          from { opacity: 0; transform: translateY(8px); }
          to   { opacity: 1; transform: translateY(0); }
        }
        .jtl-circle  { opacity: 0; animation: jtlCircle 0.30s ease-out forwards; }
        .jtl-hline   { transform-origin: left center;  transform: scaleX(0); animation: jtlHLine 0.45s ease-out forwards; }
        .jtl-vline   { transform-origin: top center;   transform: scaleY(0); animation: jtlVLine 0.30s ease-out forwards; }
        .jtl-card-ev { opacity: 0; animation: jtlCard  0.35s ease-out forwards; }
      `}</style>

      <section
        id="journey"
        className="relative flex flex-col text-white bg-cover bg-center bg-no-repeat"
        style={{
          backgroundImage: `url('${process.env.PUBLIC_URL}${bgImage}')`,
          height: '100dvh',
          maxHeight: '100dvh',
          overflow: 'hidden',
          boxSizing: 'border-box',
        }}
      >
        <div className="absolute inset-0 bg-black/60" />

        {/* Heading */}
        <div className="relative z-[1] flex-shrink-0 mx-auto max-w-3xl px-4 text-center pb-8" style={{ paddingTop: '10vh' }}>
          <h1 className="text-5xl font-bold">MY JOURNEY</h1>
          <p className="mt-3 text-white/50 text-base tracking-wide">A timeline of milestones, growth, and experiences</p>
          <hr className="mx-auto mt-6 w-48 border-t-4 border-white/20" />
        </div>

        {/* Single card */}
        <div className="relative z-[1] flex-1 min-h-0 flex items-stretch px-4 pb-8 w-full" style={{ boxSizing: 'border-box' }}>
          <div className="flex items-stretch justify-center gap-5 w-full">

            {/* Year label + counter — outside boundary on the left */}
            <div className="flex-shrink-0 w-16 text-right pt-3 select-none">
              <span className="text-3xl font-bold text-webtheme leading-none block">
                {currentData.year}
              </span>
              <span className="text-white/30 text-xs mt-1 block">
                {displayIndex + 1} / {timelineData.length}
              </span>
            </div>

            {/* Boundary */}
            <div className="flex flex-col border border-white/20 rounded-xl bg-white/5 backdrop-blur-sm overflow-hidden" style={{ width: '70vw', height: '50vh', flexShrink: 0 }}>

              {/* Header: event count only */}
              <div className="flex items-center px-5 py-3 border-b border-white/10">
                <span className="text-white/50 text-sm italic">
                  {currentData.events.length > 0
                    ? `${currentData.events.length} event${currentData.events.length !== 1 ? 's' : ''}`
                    : 'No events recorded'}
                </span>
              </div>

              {/* Carousel content wrapper — carries the slide animation */}
              <div className={`flex-1 min-h-0 overflow-hidden ${carouselClass}`} onAnimationEnd={handleAnimationEnd}>
                {/* key remounts events so animations replay on every year change */}
                <div key={`events-${animKey}`} className="h-full overflow-hidden">
                  {currentData.events.length === 0 ? (
                    <p className="text-white/30 text-sm italic text-center py-6">—</p>
                  ) : (
                    <div className="px-5 pt-5 pb-6">
                      {/* Timeline row: hline at top, cards hang below */}
                      <div className="relative flex items-start justify-around">
                        {/* Horizontal timeline line at top */}
                        <div
                          className="jtl-hline absolute top-[9px] inset-x-0 h-px bg-white/40"
                          style={{ animationDelay: '0.10s' }}
                        />
                        {/* Single circle dot at the left start of the line */}
                        <div
                          className="jtl-circle absolute left-0 top-0 w-[18px] h-[18px] rounded-full bg-white shadow-[0_0_10px_rgba(255,255,255,0.5)]"
                          style={{ animationDelay: '0s' }}
                        />
                        {currentData.events.map((event, ei) => {
                          const d = ei * 0.18;
                          return (
                            <div key={ei} className="relative z-10 flex flex-col items-center flex-1 min-w-0 px-2 pt-[9px]">
                              {/* Vertical connector down from the hline */}
                              <div
                                className="jtl-vline w-px bg-white/40"
                                style={{ height: '24px', animationDelay: `${d + 0.30}s` }}
                              />
                              {/* Event card below */}
                              <div
                                className={`jtl-card-ev max-w-[180px] w-full rounded-lg px-3 py-2 mt-2 text-center ${event.bgColor} ${event.textColor}`}
                                style={{ animationDelay: `${d + 0.55}s` }}
                              >
                                <p className="font-bold text-sm">{event.title}</p>
                                {event.description && (
                                  <p className="text-xs mt-1 whitespace-pre-line opacity-80">
                                    {event.description}
                                  </p>
                                )}
                              </div>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  )}
                </div>
              </div>

            </div>

            {/* Nav buttons — outside boundary on the right, full height */}
            <div className="flex-shrink-0 flex flex-col items-center justify-center gap-2 self-stretch">
              {/* Up — newer year */}
              <button
                type="button"
                onClick={() => navigate('prev')}
                disabled={displayIndex === 0 || phase !== 'idle'}
                aria-label="Newer year"
                className="flex items-center justify-center w-8 h-8 rounded-full bg-white/10 hover:bg-webtheme hover:text-black transition-colors duration-200 text-white disabled:opacity-25 disabled:cursor-not-allowed"
              >
                <svg viewBox="0 0 20 20" fill="currentColor" width={14} height={14}>
                  <path fillRule="evenodd" d="M14.707 12.707a1 1 0 01-1.414 0L10 9.414l-3.293 3.293a1 1 0 01-1.414-1.414l4-4a1 1 0 011.414 0l4 4a1 1 0 010 1.414z" clipRule="evenodd" />
                </svg>
              </button>

              {/* Down — older year */}
              <button
                type="button"
                onClick={() => navigate('next')}
                disabled={displayIndex === timelineData.length - 1 || phase !== 'idle'}
                aria-label="Older year"
                className="flex items-center justify-center w-8 h-8 rounded-full bg-white/10 hover:bg-webtheme hover:text-black transition-colors duration-200 text-white disabled:opacity-25 disabled:cursor-not-allowed"
              >
                <svg viewBox="0 0 20 20" fill="currentColor" width={14} height={14}>
                  <path fillRule="evenodd" d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z" clipRule="evenodd" />
                </svg>
              </button>
            </div>

          </div>
        </div>
      </section>
    </>
  );
};

export default JourneySection;
